package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.util.Arrays;
import java.util.Iterator;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private CSVRecord csvRecord;
    private String[] values;
    private Map<String, Integer> mapping;
    private String comment;
    private long recordNumber;

    @BeforeEach
    public void setUp() throws Exception {
        values = new String[] { "value1", "value2", "value3" };
        mapping = mock(Map.class);
        comment = "comment";
        recordNumber = 123L;

        Constructor<CSVRecord> constructor = CSVRecord.class.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
        csvRecord = constructor.newInstance(values, mapping, comment, recordNumber);
    }

    @Test
    public void testIterator_containsAllValues() {
        Iterator<String> iterator = csvRecord.iterator();
        assertNotNull(iterator);

        int index = 0;
        while (iterator.hasNext()) {
            String val = iterator.next();
            assertEquals(values[index], val);
            index++;
        }
        assertEquals(values.length, index);
    }

    @Test
    public void testIterator_emptyValues() throws Exception {
        // Create CSVRecord with empty values array
        Constructor<CSVRecord> constructor = CSVRecord.class.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
        CSVRecord emptyRecord = constructor.newInstance(new String[0], mapping, comment, recordNumber);

        Iterator<String> iterator = emptyRecord.iterator();
        assertNotNull(iterator);
        assertFalse(iterator.hasNext());
    }

    @Test
    public void testIterator_reflectionAccess() throws Exception {
        // Use reflection to invoke private field 'values' and change it, then test iterator
        Field valuesField = CSVRecord.class.getDeclaredField("values");
        valuesField.setAccessible(true);
        String[] newValues = new String[] { "a", "b" };
        valuesField.set(csvRecord, newValues);

        Iterator<String> iterator = csvRecord.iterator();
        assertNotNull(iterator);

        int count = 0;
        while (iterator.hasNext()) {
            assertEquals(newValues[count], iterator.next());
            count++;
        }
        assertEquals(newValues.length, count);
    }
}
